',{id:"xref_pisa_scores_vs_gdp_per_capita",title:"PISA education scores vs. GDP per capita by country - does wealth buy learning?",sub:"Singapore: PISA math 575, GDP per capita $80K. Estonia: PISA 540, GDP $31K. USA: PISA 474, GDP $80K. The US and Singapore have identical GDP per capita but a 101-point PISA gap. Money buys inputs, not outputs. The most important variable is not spending - it is teacher quality and selection.",type:"XREF",geo:"worldwide",fmt:"Scatter plot",tbl:"OECD PISA 2022 results + World Bank GDP per capita (both public)",section:"Education",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["pct_bachelors","expenditure_per_pupil"],join:["rd_pct_gdp","net_migration_rate","per_capita_health_spending"],sc:{emotional:7,relatability:6,surprise:8,tension:5,visual:5,data_ready:8,originality:6},vs:63,tags:"PISA scores GDP per capita country Singapore 575 $80K Estonia 540 $31K USA 474 $80K 101-point gap money inputs not outputs teacher quality selection OECD PISA 2022 World Bank"}',
',{id:"xref_school_discipline_rate_vs_race",title:"School suspension rate by race by state - the school-to-prison pipeline geography",sub:"Black students suspended at 3.1x the rate of white students nationally. Mississippi: 4.8x. Wisconsin: 4.4x. The racial suspension gap is largest in Northern states with progressive reputations - not the South. Suspended students are 3x more likely to be involved in the juvenile justice system within one year.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"US DOE Civil Rights Data Collection 2021-2022 school discipline (public biennial)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["expenditure_per_pupil","pct_hs_grad"],join:["pct_bachelors","rep_pct","median_household_income"],sc:{emotional:9,relatability:5,surprise:8,tension:8,visual:5,data_ready:8,originality:7},vs:78,tags:"school suspension rate race state Black 3.1x white Mississippi 4.8x Wisconsin 4.4x Northern progressive South school-to-prison 3x juvenile justice DOE Civil Rights Data Collection 2021"}',
',{id:"xref_school_funding_equity_vs_outcomes",title:"School funding equity (rich vs. poor district ratio) vs. test score gap by state - closing the gap requires closing the funding gap",sub:"New York state: wealthy districts spend 2.8x more per pupil than poor districts. Test score gap between rich and poor: 31 percentile points. Vermont: 1.1x funding ratio, 14 point gap. The funding equity-outcome equity correlation (r=0.72) is among the strongest in education policy data.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"EdBuild school funding equity data + Stanford Education Opportunity Project scores (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["expenditure_per_pupil","pct_hs_grad"],join:["pct_bachelors","median_household_income","rep_pct"],sc:{emotional:8,relatability:7,surprise:7,tension:7,visual:5,data_ready:7,originality:6},vs:70,tags:"school funding equity rich poor district ratio test score state New York 2.8x 31 percentile Vermont 1.1x 14 r=0.72 EdBuild Stanford Education Opportunity Project closing gap"}',
',{id:"xref_early_childhood_investment_vs_lifetime_earnings",title:"Early childhood education investment per child vs. adult earnings 30 years later - Heckman curve",sub:"The Perry Preschool Project: $8,000 per child investment in 1962 dollars yielded $195,000 in lifetime economic returns per participant (2023 dollars). The return on investment is 7-13% annually - higher than any financial instrument available to governments. Nobel economist James Heckman: returns decline with age of intervention.",type:"CHART",geo:"us_national",fmt:"Line chart",tbl:"Perry Preschool Project longitudinal data + Heckman Equation research (public academic)",section:"Education",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["expenditure_per_pupil","pct_bachelors"],join:["median_household_income","pct_hs_grad","pct_on_snap"],sc:{emotional:7,relatability:6,surprise:7,tension:5,visual:5,data_ready:7,originality:7},vs:61,tags:"early childhood education investment adult earnings Perry Preschool $8000 $195000 lifetime returns 7-13% annually highest ROI Heckman curve age of intervention declines Nobel Perry Project"}',
',{id:"xref_teacher_diversity_vs_student_outcomes",title:"Teacher racial diversity vs. student of color test score gap by district - do same-race teachers matter?",sub:"Black students assigned to at least one Black teacher in K-3 are 13% more likely to enroll in college. Districts where teacher diversity matches student diversity within 10 percentage points show 19% smaller racial test score gaps. The representation effect is one of the most robust findings in education research.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"US DOE Civil Rights Data Collection + Stanford Ed Opportunity Project (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["expenditure_per_pupil","avg_teacher_salary"],join:["pct_bachelors","median_household_income","rep_pct"],sc:{emotional:8,relatability:6,surprise:7,tension:6,visual:4,data_ready:7,originality:7},vs:67,tags:"teacher diversity student outcomes Black students 13% more likely college matches within 10% 19% smaller racial gap representation effect robust education research DOE Civil Rights Stanford"}',
',{id:"global_adult_literacy_rate_map",title:"Adult literacy rate by country 2024 - the foundation all other development rests on",sub:"Niger: 37% adult literacy - one of the lowest in the world. Chad: 26%. South Sudan: 34%. Finland: 100%. Iceland: 100%. The literacy map is the development map, the income map, and the gender equality map simultaneously - all four correlate above 0.80 with adult literacy.",type:"MAP",geo:"worldwide",fmt:"World choropleth",tbl:"UNESCO Institute for Statistics adult literacy data 2024 (public)",section:"Education",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["pct_hs_grad","pct_bachelors"],join:["birth_rate","net_migration_rate","per_capita_health_spending"],sc:{emotional:8,relatability:5,surprise:6,tension:5,visual:8,data_ready:8,originality:3},vs:62,tags:"adult literacy rate country 2024 Niger 37% Chad 26% South Sudan 34% Finland Iceland 100% development income gender equality correlate 0.80 UNESCO Institute Statistics"}',
',{id:"xref_summer_learning_loss_vs_income",title:"Summer learning loss by income level vs. full-year learning gain - the 3-month reversal",sub:"Low-income students lose an average 2.6 grade level months of reading over summer. High-income students gain 1 month. The annual academic gap between income groups is driven more by summer divergence than school-year differences. Schools that do close the gap often see it reopen each September.",type:"CHART",geo:"us_national",fmt:"Bar chart",tbl:"NWEA MAP Growth seasonal learning data + RAND summer learning study (public research)",section:"Education",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["expenditure_per_pupil","pct_on_snap"],join:["median_household_income","pct_bachelors","pct_hs_grad"],sc:{emotional:7,relatability:6,surprise:8,tension:5,visual:6,data_ready:7,originality:6},vs:63,tags:"summer learning loss income low-income 2.6 grade months reading high-income +1 month annual gap summer divergence school-year NWEA MAP Growth RAND summer learning"}',
',{id:"xref_school_chronic_absenteeism_vs_outcomes",title:"Chronic absenteeism rate by district vs. 3rd grade reading proficiency - missing school predicts everything",sub:"Districts with chronic absenteeism above 20% of students (missing 10%+ of school days) have 3rd grade reading proficiency rates 31% lower than comparable districts under 10% absenteeism. Chronic absenteeism doubled post-COVID and has not recovered. It is the leading predictor of high school dropout, above poverty level.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"US DOE Chronic Absenteeism data 2022-2023 + NAEP state reading scores (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_hs_grad","expenditure_per_pupil"],join:["median_household_income","pct_on_snap","rural_population_pct"],sc:{emotional:8,relatability:7,surprise:7,tension:6,visual:4,data_ready:8,originality:6},vs:69,tags:"chronic absenteeism school 20%+ 31% lower proficiency 10% doubled COVID not recovered dropout predictor above poverty DOE Chronic Absenteeism NAEP state reading 2022 2023"}',
',{id:"xref_college_major_vs_lifetime_earnings_gender",title:"College major vs. median lifetime earnings by gender - the major gap and the gender gap intersect",sub:"Male petroleum engineering graduates: $188K median lifetime earnings. Female social work graduates: $39K. But even within STEM: female computer science graduates earn 82 cents to male CS graduates. The earnings gap exists within majors AND across majors - with women overrepresented in lower-paying fields AND underpaid within them.",type:"CHART",geo:"us_national",fmt:"Scatter plot",tbl:"Census ACS earnings by field of bachelor degree + gender (Census API public)",section:"Education",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["pct_bachelors","female_lfp_rate"],join:["median_household_income","manufacturing_hourly_wages_state","pct_hs_grad"],sc:{emotional:8,relatability:8,surprise:7,tension:6,visual:5,data_ready:8,originality:6},vs:72,tags:"college major lifetime earnings gender petroleum $188K social work $39K CS 82 cents STEM overrepresented underpaid within across majors ACS earnings field bachelor gender"}',
',{id:"xref_school_start_time_vs_academic_performance",title:"School start time vs. student academic performance and mental health by district",sub:"Districts that shifted from 7:30 AM to 8:30 AM start times (Seattle, Minneapolis) showed 4.5% improvement in grades and 29% reduction in teen depression symptoms within 2 years. Adolescent sleep biology requires later start times. The evidence is overwhelming - but change is blocked by transportation budget and parent schedule concerns.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"American Academy of Pediatrics start time data + RAND school hours study (public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["expenditure_per_pupil","pct_hs_grad"],join:["median_household_income","rural_population_pct","pct_bachelors"],sc:{emotional:8,relatability:8,surprise:7,tension:5,visual:4,data_ready:7,originality:7},vs:70,tags:"school start time academic performance 7:30 to 8:30 AM Seattle Minneapolis 4.5% grades 29% depression symptoms 2 years sleep biology transportation budget RAND school hours AAP"}',
',{id:"xref_for_profit_college_vs_debt_outcomes",title:"For-profit college enrollment vs. student debt default rate by state - where the debt trap concentrates",sub:"States with higher for-profit college enrollment share have 3-year student loan default rates 2.4x higher than states with low for-profit enrollment. For-profit college graduates have median earnings only 8% higher than high school graduates - vs. 65% higher for public 4-year graduates. The for-profit premium is negative after debt costs.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"NCES IPEDS for-profit enrollment + ED loan default rate cohort data (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["student_loans_outstanding","pct_bachelors"],join:["median_household_income","pct_hs_grad","pct_under_25k"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:4,data_ready:7,originality:6},vs:68,tags:"for-profit college debt default state 2.4x higher 8% premium 65% public 4-year negative after debt costs trap NCES IPEDS ED loan default cohort for-profit enrollment share"}',
',{id:"xref_bilingual_education_vs_english_acquisition",title:"Bilingual vs. English-only immersion programs vs. English language acquisition speed - what the research says",sub:"Longitudinal studies: students in well-implemented bilingual programs reach English proficiency 2-3 years earlier than English-only immersion peers, by 5th grade. The counter-intuitive result: maintaining L1 while learning English accelerates English acquisition. But implementation quality varies enormously and most districts lack resources for quality bilingual programs.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"AERA bilingual education meta-analysis data + state ELL proficiency rates (public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["language_diversity_index","pct_hs_grad"],join:["pct_bachelors","median_household_income","net_migration_rate"],sc:{emotional:6,relatability:5,surprise:8,tension:5,visual:4,data_ready:6,originality:7},vs:57,tags:"bilingual vs English-only immersion acquisition speed 2-3 years earlier 5th grade L1 maintains accelerates counter-intuitive implementation quality resources AERA meta-analysis ELL proficiency"}',
',{id:"xref_special_ed_identification_rate_vs_income",title:"Special education identification rate vs. median income by district - are poor kids misidentified?",sub:"Low-income districts identify 16.2% of students for special education. High-income districts: 11.4%. The identification gap goes in both directions: low-income districts over-identify for behavioral categories (emotional disturbance) and under-identify for learning disabilities (dyslexia) that require expensive intervention.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"US DOE Civil Rights Data Collection special education + ACS income (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["expenditure_per_pupil","pct_hs_grad"],join:["median_household_income","pct_on_snap","rural_population_pct"],sc:{emotional:7,relatability:5,surprise:7,tension:5,visual:4,data_ready:7,originality:7},vs:60,tags:"special education identification income district low-income 16.2% high-income 11.4% over-identify behavioral under-identify dyslexia expensive intervention DOE Civil Rights Data Collection ACS"}',
',{id:"xref_homeschool_growth_vs_covid_policy",title:"Homeschool enrollment growth by state 2019-2024 - COVID as the great education diversifier",sub:"National homeschool enrollment: 2019: 2.5 million. 2024: 3.3 million (32% increase). Growth highest in states with longest school closures in 2020-2021. Black homeschool enrollment grew 73% - the fastest growth of any group. The COVID school closure decision permanently changed a portion of the education market.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"Census Household Pulse Survey homeschool data + NCES homeschool estimates (public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["pct_hs_grad","pct_bachelors"],join:["median_household_income","rep_pct","rural_population_pct"],sc:{emotional:6,relatability:7,surprise:8,tension:4,visual:6,data_ready:7,originality:7},vs:63,tags:"homeschool enrollment growth state 2019 2024 2.5M 3.3M 32% longest closures Black 73% fastest COVID permanent education market change Census Household Pulse NCES estimates"}',
',{id:"xref_graduate_degree_premium_vs_undergraduate",title:"Graduate degree wage premium vs. undergraduate premium 1980-2024 - the credential inflation race",sub:"1980: bachelor degree wage premium over high school: 38%. 2024: 65%. But graduate degree premium over bachelor: 1980: 18%. 2024: 41%. The premium for each credential has grown but the graduate degree premium grew faster. The result: more credential inflation and longer time before full workforce entry.",type:"CHART",geo:"us_national",fmt:"Line chart",tbl:"BLS wage data by education level 1980-2024 + Census SIPP earnings (both public)",section:"Education",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["pct_bachelors","manufacturing_hourly_wages_state"],join:["median_household_income","pct_hs_grad","student_loans_outstanding"],sc:{emotional:6,relatability:7,surprise:7,tension:5,visual:6,data_ready:8,originality:5},vs:61,tags:"graduate degree wage premium undergraduate 1980 2024 bachelor 38% 65% graduate 18% 41% credential inflation faster longer workforce entry BLS education level Census SIPP earnings"}',
',{id:"xref_school_counselor_ratio_vs_college_enrollment",title:"School counselor-to-student ratio vs. college enrollment rate by district - counseling as access",sub:"Districts with 1:250 counselor-to-student ratios (ASCA recommended) have college enrollment rates 22% higher than comparable districts with 1:500 ratios, controlling for income. The national average is 1:408. The college access gap is partly a counseling capacity gap - low-income districts have the highest student loads and lowest counseling ratios.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"US DOE Civil Rights Data Collection counselor ratios + NSC college enrollment by district (public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_bachelors","expenditure_per_pupil"],join:["pct_hs_grad","median_household_income","pct_on_snap"],sc:{emotional:7,relatability:5,surprise:7,tension:5,visual:4,data_ready:7,originality:7},vs:60,tags:"school counselor ratio college enrollment district 1:250 ASCA 22% higher 1:500 1:408 national access gap capacity low-income highest load DOE Civil Rights NSC college enrollment"}',
',{id:"xref_algebra_access_vs_long_term_outcomes",title:"8th grade algebra access by income level vs. STEM college completion - the gatekeeper class",sub:"Low-income students access 8th grade algebra at 55% the rate of high-income students. Among students who complete Algebra I by 8th grade, 81% eventually complete a college degree vs. 39% who first take it in 9th grade. The single class of Algebra I is the strongest predictor of college completion available to middle school educators.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"US DOE Civil Rights Data Collection algebra access + NSC college completion (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_bachelors","expenditure_per_pupil"],join:["pct_hs_grad","median_household_income","pct_on_snap"],sc:{emotional:8,relatability:7,surprise:8,tension:5,visual:4,data_ready:7,originality:7},vs:70,tags:"algebra 8th grade access income STEM college completion low-income 55% Algebra I 81% degree 39% 9th grade single class predictor DOE Civil Rights NSC college completion gatekeeper"}'
